import type { Drug, ClinicalSummary, Hazardous, Extravasation, Sequencing, Emetogenic, Toxicities, CADDDefault } from '@/lib/iv-reference-types';

// ==========================================
// CLINICAL SUMMARIES
// ==========================================
const CLINICAL_SUMMARIES: Record<string, ClinicalSummary> = {
  "Cisplatin": { pearls: "Highly emetogenic, requires aggressive pre/post hydration. Nephrotoxic and ototoxic.", dosing: "Varies (e.g., 50-100 mg/m2 IV q3-4 weeks).", monitoring: "SCr, BUN, Mg, K, Audiometry, CBC." },
  "Carboplatin": { pearls: "Dosed via Calvert formula (Target AUC). Hypersensitivity can occur after multiple doses.", dosing: "Target AUC 4-6 IV q3-4 weeks.", monitoring: "CBC (especially platelets), SCr, LFTs." },
  "Oxaliplatin": { pearls: "Cold-induced neuropathy is a hallmark toxicity. Exacerbated by cold drinks/air.", dosing: "85-130 mg/m2 IV q2-3 weeks.", monitoring: "CBC, neuropathy symptoms, LFTs." },
  "Paclitaxel": { pearls: "Requires non-PVC tubing/bags and in-line filter. High risk of hypersensitivity.", dosing: "175 mg/m2 IV q3 weeks or 80 mg/m2 weekly.", monitoring: "CBC, neuropathy, vital signs (infusion rxn)." },
  "Docetaxel": { pearls: "Fluid retention risk; premedicate with dexamethasone. Non-PVC tubing required.", dosing: "75-100 mg/m2 IV q3 weeks.", monitoring: "CBC, LFTs, weight/edema." },
  "Doxorubicin": { pearls: "Potent vesicant. Lifetime cumulative dose limit (usually 450-550 mg/m2) due to cardiotoxicity. Red urine.", dosing: "40-60 mg/m2 IV q3-4 weeks.", monitoring: "ECHO/MUGA (LVEF), CBC, LFTs." },
  "Cyclophosphamide": { pearls: "Hemorrhagic cystitis risk (hydrate well, +/- mesna for high doses).", dosing: "Varies widely (e.g., 600 mg/m2 IV q2-3 weeks).", monitoring: "CBC, urinalysis, BUN/SCr." },
  "Fluorouracil": { pearls: "DPD deficiency increases toxicity risk. Continuous infusion = higher hand-foot syndrome risk.", dosing: "Varies (bolus vs continuous, e.g., 2400 mg/m2 over 46h).", monitoring: "CBC, LFTs, oral mucosa." },
  "Pembrolizumab": { pearls: "Immune-mediated toxicities (pneumonitis, colitis, endocrinopathies).", dosing: "200 mg q3w or 400 mg q6w IV.", monitoring: "Thyroid panel, LFTs, SCr, respiratory sx." },
  "Vancomycin": { pearls: "Red man syndrome with rapid infusion (premedicate or slow rate). AUC/MIC targeting is preferred per ASHP/IDSA/SIDP 2020 guidelines.", dosing: "15-20 mg/kg IV q8-12h (adjust for renal function; AUC-guided dosing preferred).", monitoring: "AUC/MIC monitoring preferred (target AUC24 400–600 mg·h/L; trough-only monitoring no longer recommended as primary strategy). SCr baseline and at least q48–72h. Auditory function for prolonged courses." },
  "Immune Globulin Intravenous (IVIG)": { pearls: "Do not mix with other drugs. Infusion rate is concentration and brand-dependent. Risk of renal failure and thrombosis.", dosing: "Varies widely by indication.", monitoring: "Renal function, urine output, vital signs, signs of thrombosis." },
  "Iron Sucrose": { pearls: "Test dose not required. Monitor for hypotension during infusion.", dosing: "Typically 100-300 mg per dose.", monitoring: "BP, HR, ferritin, TSAT." },
  "Iron Dextran": { pearls: "Boxed warning for fatal anaphylaxis. A 25 mg TEST DOSE is mandatory before the full therapeutic dose.", dosing: "Varies (can be total dose infusion).", monitoring: "Observe for signs of anaphylaxis for at least 1 hour." },
  "Ferumoxytol": { pearls: "Boxed warning for anaphylaxis. Must be diluted and infused over at least 15 minutes (no IV push). Can alter MRI imaging.", dosing: "510 mg IV x 2 doses (3-8 days apart).", monitoring: "Monitor for hypersensitivity for at least 30 mins post-infusion." },
  "Ampicillin-Sulbactam": { pearls: "Combination penicillin/beta-lactamase inhibitor (2:1 ratio ampicillin:sulbactam). Active against many beta-lactamase-producing organisms including MSSA, Enterococcus, and Acinetobacter (sulbactam-specific intrinsic activity). NOT reliable for MRSA or Pseudomonas. Preferred over ampicillin alone for polymicrobial and abdominal infections.", dosing: "Mild-moderate infections: 1.5–3 g IV q6h. Severe/Acinetobacter: 3 g IV q4h (high-dose). Renal adjustment required (CrCl <30 mL/min).", monitoring: "SCr/BUN, LFTs (cholestatic hepatitis with prolonged use), CBC, signs of C. diff. Observe for hypersensitivity/anaphylaxis — cross-reactivity with other penicillins and some cephalosporins." },

  // ===== Phase 1 expansion summaries =====
  "Ceftolozane-Tazobactam": { pearls: "Antipseudomonal cephalosporin + beta-lactamase inhibitor. Reserve for MDR Pseudomonas and ESBL Enterobacterales. NOT active against KPC/MBL CRE. Higher dose (3 g q8h) for HABP/VABP per ASPECT-NP.", dosing: "cIAI/cUTI: 1.5 g IV q8h × 7-14d. HABP/VABP: 3 g IV q8h × 8-14d. Adjust for CrCl <50 mL/min.", monitoring: "SCr (renal dose adjust), CBC, LFTs. Watch for C. diff." },
  "Ceftazidime-Avibactam": { pearls: "First-line for KPC-producing CRE per IDSA AMR Guidance 2024. Combine with aztreonam if MBL co-production suspected. Resistance can emerge on therapy — monitor cultures.", dosing: "2.5 g IV q8h (CrCl >50). Reduce dose for renal impairment (e.g., 1.25 g q8h CrCl 31-50, 0.94 g q12h CrCl 16-30).", monitoring: "SCr daily, CBC, LFTs, follow-up cultures for resistance emergence." },
  "Meropenem-Vaborbactam": { pearls: "Vaborbactam restores meropenem activity vs KPC-producing CRE. NOT active against MBL or OXA-48. Compatible only with NS — do NOT use D5W.", dosing: "4 g IV q8h infused over 3 hours (CrCl >50). Renal adjustment required.", monitoring: "SCr (renal adjust), LFTs, CBC, follow cultures." },
  "Cefiderocol": { pearls: "Siderophore cephalosporin — uses bacterial iron transport. Active vs MBL/OXA-48 CRE, MDR Pseudomonas, MDR Acinetobacter, Stenotrophomonas. CREDIBLE-CR mortality signal in Acinetobacter/critically ill — verify clinical context before use.", dosing: "2 g IV q8h infused over 3 hours (CrCl >60). Adjust for renal impairment AND for augmented renal clearance.", monitoring: "SCr, follow-up cultures, clinical response. Daily mental status and infection markers." },
  "Polymyxin B": { pearls: "Salvage for MDR-GN (Acinetobacter, Pseudomonas, CRE). Dose in UNITS not mg — verify with pharmacy. Significant nephrotoxicity (~30%) and reversible neurotoxicity (paresthesias). Combination therapy generally preferred.", dosing: "Loading 2-2.5 mg/kg (20,000-25,000 units/kg) → maintenance 1.5 mg/kg/day divided q12h. NO renal dose adjustment per recent PK data — but monitor closely.", monitoring: "SCr daily, neurological assessment. Trough levels not routine but emerging." },
  "Colistimethate": { pearls: "Salvage for MDR-GN. Dose in colistin base activity (CBA) mg — NOT colistimethate mg (huge difference). Significant nephrotoxicity. Avoid concurrent nephrotoxins. Inhaled formulation also exists for cystic fibrosis Pseudomonas.", dosing: "Loading 300 mg CBA → maintenance 2.5-5 mg CBA/kg/day divided q8-12h. Renal dose adjustment required.", monitoring: "SCr daily, electrolytes, neurological status (paresthesias, dizziness)." },
  "Trimethoprim-Sulfamethoxazole": { pearls: "First-line for PJP (Pneumocystis jirovecii pneumonia). Significant hyperkalemia and SCr elevation (creatinine secretion inhibition — not true AKI). Severe SJS/TEN risk. D5W ONLY for IV dilution.", dosing: "PJP treatment: 15-20 mg/kg/day TMP component IV divided q6-8h × 21 days. PJP prophylaxis: 1 SS PO daily. Renal adjustment for CrCl <30 mL/min.", monitoring: "K, SCr (true AKI vs creatinine secretion artifact), CBC (cytopenias), LFTs, skin (SJS/TEN). Folinic acid supplementation in long courses." },
  "Caspofungin": { pearls: "First-line empiric for invasive candidiasis in non-neutropenic patients. NO renal dose adjustment. Reduce maintenance dose (35 mg/day after 70 mg load) in moderate hepatic impairment (Child-Pugh B). NOT compatible with D5W.", dosing: "70 mg IV load → 50 mg IV q24h maintenance. ↑ maintenance to 70 mg in patients >80 kg or on enzyme inducers (rifampin, phenytoin).", monitoring: "LFTs weekly, infusion-site reactions, follow cultures. Generally well tolerated." },
  "Anidulafungin": { pearls: "Echinocandin with NO renal or hepatic dose adjustment — preferred when both renal and hepatic function are uncertain. Slow rate (≤1.1 mg/min) to avoid histamine-mediated infusion reaction (flushing, hypotension).", dosing: "Candidemia: 200 mg IV load → 100 mg IV q24h × ≥14 days post-clearance. Esophageal candidiasis: 100 mg load → 50 mg q24h.", monitoring: "LFTs weekly, infusion-site reactions, follow cultures." },
  "Isavuconazonium": { pearls: "Triazole antifungal with broad coverage including Aspergillus AND Mucorales. NO SBECD vehicle (unlike voriconazole) — preferred in renal impairment. Significant CYP3A4 interactions. Mandatory in-line filter. Linear PK — therapeutic drug monitoring not required.", dosing: "Loading: 372 mg IV q8h × 6 doses (48 hours) → 372 mg IV q24h. Same prodrug-to-active conversion as oral. NO renal dose adjustment.", monitoring: "LFTs (hepatotoxicity), QTc (shortens QT — opposite of voriconazole). CYP3A4 drug interaction screen MANDATORY." },
  "Amphotericin B Liposomal": { pearls: "Preferred over conventional AmB due to ~50% reduction in nephrotoxicity. D5W ONLY for dilution (NS causes precipitation). Mandatory ≥1 micron in-line filter. Pre-medicate with APAP + diphenhydramine ± hydrocortisone for infusion reactions. NIOSH Group 1.", dosing: "3-5 mg/kg/day IV (cryptococcal meningitis 6 mg/kg, mucormycosis 5-10 mg/kg). Higher doses for resistant fungi.", monitoring: "Daily SCr, K, Mg (electrolyte wasting), CBC, LFTs. Aggressive electrolyte replacement (K, Mg). Pre-hydration with 500-1000 mL NS." },
  "Acyclovir": { pearls: "Crystalline nephropathy if rapid infusion or under-hydrated. Dose by IBW (overweight patients). Encephalopathy in renal impairment — adjust dose carefully. NEVER bolus or IM.", dosing: "HSV encephalitis: 10 mg/kg IV q8h × 14-21 days (IBW). VZV: 10 mg/kg q8h. Mucocutaneous HSV: 5 mg/kg q8h. Renal adjust for CrCl <50 mL/min.", monitoring: "SCr q48h, CBC, neurological assessment. Hydrate with 500 mL NS pre-infusion. Infuse over ≥60 mins." },
  "Ganciclovir": { pearls: "NIOSH Group 1 hazardous — handle as antineoplastic with CSTD. Dose-limiting neutropenia and thrombocytopenia. Mutagenic/teratogenic — use barrier contraception. Dose-adjust for renal function (most common error).", dosing: "CMV induction: 5 mg/kg IV q12h × 14-21 days. Maintenance: 5 mg/kg IV q24h. Renal dose adjust for CrCl <70 mL/min.", monitoring: "ANC and platelets ≥2-3×/week. Hold for ANC <500 or platelets <25,000. SCr q48-72h. Consider G-CSF for neutropenia." },
  "Foscarnet": { pearls: "Resistant HSV/CMV salvage. Pyrophosphate analog — chelates divalent cations causing severe Ca/Mg/K/PO4 derangements. Significant nephrotoxicity. Pump-controlled rate MANDATORY (max 1 mg/kg/min). Pre-hydrate with NS.", dosing: "CMV induction: 60 mg/kg IV q8h or 90 mg/kg IV q12h × 14-21 days. Maintenance: 90-120 mg/kg IV q24h. Renal dose adjust required.", monitoring: "SCr daily, ionized Ca / Mg / K / PO4 daily during induction. Replete electrolytes proactively. Genital ulceration — dilute peripheral concentration to ≤12 mg/mL." },
  "Remdesivir": { pearls: "COVID-19 antiviral. SBECD vehicle accumulates in renal impairment — avoid if eGFR <30 mL/min (relative contraindication; benefit may outweigh in select cases). Hepatotoxicity — discontinue if ALT >10× ULN. Hypersensitivity reactions reported.", dosing: "200 mg IV × 1 → 100 mg IV q24h × 4 days (or until discharge). Total 5-day course.", monitoring: "LFTs daily during therapy. SCr (drug + vehicle accumulation). Infusion reactions during/after dose." },

  // ===== Phase 2 expansion summaries (Critical Care) =====
  "Norepinephrine": { pearls: "First-line vasopressor for septic shock per Surviving Sepsis 2021. Central line strongly preferred — peripheral acceptable for short-duration (≤6h) bridging if no central access. Vesicant — extravasation antidote phentolamine 5-10 mg in 10 mL NS subQ around site within 12h.", dosing: "0.01-3 mcg/kg/min titrated to MAP ≥65 mmHg (typical 0.05-1 mcg/kg/min). No max dose, but >0.5-1 mcg/kg/min suggests need for adjunct (vasopressin, hydrocortisone).", monitoring: "MAP/SBP continuously, lactate q4-6h, IV site (extravasation), peripheral perfusion (limb ischemia risk at high doses)." },
  "Epinephrine": { pearls: "Three distinct uses with three distinct concentrations: anaphylaxis (1:1000 IM), cardiac arrest (1:10,000 IV push), shock (titrated infusion). NEVER push 1:1000 concentration IV — fatal arrhythmia. Vesicant.", dosing: "Anaphylaxis: 0.3-0.5 mg IM (1:1000) q5-15min. Cardiac arrest: 1 mg IVP q3-5min (1:10,000). Shock infusion: 0.01-0.1 mcg/kg/min titrated.", monitoring: "MAP, HR, rhythm, lactate, glucose (transient hyperglycemia). Limb perfusion at high doses." },
  "Phenylephrine": { pearls: "Pure α₁ — no chronotropy. Useful when tachycardia limits norepinephrine (e.g., AF with RVR). Push doses (50-200 mcg) for transient hypotension during induction/anesthesia. Reflex bradycardia common.", dosing: "Push: 50-200 mcg IV (dilute to 100 mcg/mL). Continuous: 0.5-6 mcg/kg/min (typical 40-180 mcg/min). Central line preferred for prolonged use.", monitoring: "MAP, HR (reflex bradycardia), end-organ perfusion." },
  "Vasopressin": { pearls: "Septic shock add-on per Surviving Sepsis — adjunct to norepinephrine when MAP <65 despite escalating dose. Fixed-dose (0.03 units/min), NOT titrated. Doses >0.04 units/min cause coronary/mesenteric ischemia.", dosing: "Septic shock: fixed 0.03 units/min (range 0.01-0.04). Hepatorenal syndrome: 0.01 units/min titrated. NOT first-line — adjunctive only.", monitoring: "MAP, urine output, lactate. End-organ ischemia signs (mesenteric pain, ECG changes)." },
  "Nicardipine": { pearls: "Smooth, titratable BP control for hypertensive emergency. Onset 5-15 min. Phlebitis with peripheral infusion — rotate site q12h or use central line. Continue PO antihypertensive transition before stopping infusion.", dosing: "5 mg/hr initial, ↑2.5 mg/hr q5-15min as needed, max 15 mg/hr. Reduce to 3 mg/hr once BP at target.", monitoring: "BP q5min during titration → q15min once stable. HR, peripheral IV site (phlebitis)." },
  "Labetalol": { pearls: "First-line for hypertensive emergency in pregnancy and acute stroke. Mixed α/β with α:β ratio ~1:7 IV. Avoid in severe asthma, decompensated HFrEF, severe bradycardia, 2nd/3rd degree AV block. Patient supine during/after IV — orthostatic hypotension common.", dosing: "Push: 10-20 mg q10min (max 300 mg). Continuous: start 2 mg/min, titrate to 8 mg/min max. Pregnancy preeclampsia: 20 mg q10min.", monitoring: "BP, HR, signs of bronchospasm or HF decompensation." },
  "Nitroglycerin": { pearls: "PVC tubing absorbs 40-80% of NTG — use non-PVC (glass, polyolefin, polyethylene) tubing or set rate higher. Tachyphylaxis within 24-48h continuous infusion — nitrate-free interval if possible. Methemoglobinemia at high doses.", dosing: "ACS: start 5-10 mcg/min, titrate by 5-10 mcg/min q5min to symptoms (max 200 mcg/min). HF/pulm edema: similar titration. Hypertensive emergency in ACS: same.", monitoring: "BP q5min during titration, HR, headache (common), methemoglobinemia (if cyanotic on high doses)." },
  "Nitroprusside": { pearls: "Most rapid-acting and titratable IV antihypertensive — but cyanide/thiocyanate toxicity risk at doses >2 mcg/kg/min for >24-48h or in renal/hepatic impairment. Co-administer thiosulfate if prolonged. Light protection MANDATORY (cyanide release).", dosing: "Start 0.3 mcg/kg/min, titrate to BP target. Avoid >2 mcg/kg/min sustained. Max 10 mcg/kg/min for ≤10 min only.", monitoring: "BP continuously, lactate q6h (cyanide), thiocyanate level if >24h infusion (target <10 mg/dL). Mental status." },
  "Amiodarone": { pearls: "Total Day 1 dose: 1050 mg (150 mg load + 1 mg/min × 6h + 0.5 mg/min × 18h). Concentrations >2 mg/mL via CENTRAL LINE only — severe phlebitis. Long half-life ~58 days. Multiple drug interactions: warfarin (↓ dose 30-50%), digoxin (↓ dose 50%), statins (rhabdo with simvastatin >20 mg).", dosing: "VT/VF: 300 mg IVP, repeat 150 mg. Stable VT/AF rate control: 150 mg over 10 min → 1 mg/min × 6h → 0.5 mg/min × 18h. Maintenance per protocol.", monitoring: "BP and HR during loading (bradycardia, hypotension common — slow rate). LFTs, TSH, pulm function (amiodarone pulmonary toxicity), QTc baseline." },
  "Diltiazem": { pearls: "Rate control for AF/AFL. AVOID in HFrEF, WPW with AF, severe bradycardia, 2nd/3rd degree AV block. Bolus + infusion combo for rapid + sustained rate control.", dosing: "Bolus: 0.25 mg/kg over 2 min (avg 20 mg). If inadequate at 15 min, repeat 0.35 mg/kg over 2 min (avg 25 mg). Continuous: 5 mg/hr → titrate to 15 mg/hr.", monitoring: "HR, BP, signs of HF decompensation. ECG continuous during bolus." },
  "Esmolol": { pearls: "Ultra-short half-life (~9 min) — fast on/off makes it ideal when β-blockade tolerance uncertain (e.g., reactive airway disease, decompensated HF, peri-intubation tachycardia). NOT for chronic AF rate control.", dosing: "Load 500 mcg/kg over 1 min → maintenance 50-300 mcg/kg/min titrated. Re-load if dose escalation needed.", monitoring: "BP and HR continuously. Bronchospasm in reactive airway disease. Hypotension common at high doses." },
  "Adenosine": { pearls: "PSVT/SVT termination AND diagnostic for AF/AFL (transient AV block reveals atrial activity). Half-life ~10 sec — MUST push rapidly through proximal/central vein with 20 mL flush, ideally via two-syringe technique. Warn patient: transient flushing, chest pressure, sense of impending doom.", dosing: "Adult: 6 mg → 12 mg → 12 mg (max 18 mg). Pediatric: 0.1 mg/kg → 0.2 mg/kg (max 12 mg). Reduce dose 50% if central line or patient on dipyridamole/carbamazepine.", monitoring: "Continuous ECG. Brief asystole expected (3-10 sec). Have crash cart available." },
  "Heparin (UFH)": { pearls: "ISMP HIGH-ALERT — independent double-check before bolus and rate changes. NEVER confuse with insulin (look-alike vials). HIT screen if platelets drop >50% on day 5-14. Antidote: protamine 1 mg per 100 units heparin given in last 2-3h (max 50 mg).", dosing: "VTE/ACS: 80 units/kg bolus → 18 units/kg/hr titrated to aPTT or anti-Xa. Consult institutional weight-based protocol. Monitor q6h until therapeutic, then daily.", monitoring: "aPTT (target 1.5-2.5× control) or anti-Xa (target 0.3-0.7) q6h until therapeutic. CBC + platelets daily. Stool guaiac/bleeding signs." },
  "Argatroban": { pearls: "First-line for acute HIT (heparin-induced thrombocytopenia). Hepatic dose adjust required (start 0.5 mcg/kg/min if Child-Pugh B/C). Falsely elevates INR — bridge to warfarin requires overlap until INR >4 on combo, then >2 alone after stopping argatroban.", dosing: "HIT: 2 mcg/kg/min (or 0.5 if hepatic impairment), titrate to aPTT 1.5-3× baseline (max 100 sec). PCI in HIT: 350 mcg/kg bolus → 25 mcg/kg/min during PCI.", monitoring: "aPTT q2h until 2 consecutive in range, then q12-24h. Platelets daily (HIT recovery). LFTs (hepatic adjustment trigger)." },
  "Bivalirudin": { pearls: "Anticoagulation for PCI; alternative for HIT during/after PCI. Renal dose adjustment: CrCl <30 → 1 mg/kg/hr; HD → 0.25 mg/kg/hr. Half-life ~25 min — shorter than argatroban. NO antidote available.", dosing: "PCI: 0.75 mg/kg bolus → 1.75 mg/kg/hr × duration of PCI + 4h post (optional 0.2 mg/kg/hr × up to 20h after). HIT non-PCI: 0.15-0.2 mg/kg/hr titrated to aPTT 1.5-2.5× control.", monitoring: "aPTT (or ACT during PCI). Platelets, signs of bleeding. SCr (renal dose adjust)." },
  "Alteplase": { pearls: "ISMP HIGH-ALERT. STRICT inclusion/exclusion criteria — last known well <4.5h for stroke, no contraindications (recent surgery, bleeding, uncontrolled HTN). Reconstitute slowly (foaming if shaken). Do NOT mix with other meds in same line. Major bleeding risk — type and screen, IV access, BP control mandatory before infusion.", dosing: "STEMI: 100 mg over 90 min (15 mg bolus / 50 mg over 30 min / 35 mg over 60 min). Stroke: 0.9 mg/kg max 90 mg (10% bolus over 1 min, 90% over 60 min). PE: 100 mg over 2h. Cathflo (catheter clearance): 2 mg in catheter, dwell 30-120 min (max 2 doses).", monitoring: "BP q15min × 2h then q30min × 6h then q1h × 16h (stroke). Neuro checks, bleeding signs (intracranial, GI, GU, retroperitoneal). Type & screen pre-infusion." },
  "Propofol": { pearls: "Soybean/egg lecithin emulsion supports microbial growth — STRICT aseptic technique. Bottle/syringe and tubing MUST be discarded q12h per ASHP. Egg/soy allergy contraindication (controversial but standard). Propofol Infusion Syndrome (PRIS): metabolic acidosis, rhabdo, AKI, cardiac collapse — risk with >4 mg/kg/hr × >48h.", dosing: "ICU sedation: 5 mcg/kg/min initial, titrate to RASS goal (max 50 mcg/kg/min, ideally <30 to avoid PRIS). Procedural: 0.5-1 mg/kg bolus then 25-75 mcg/kg/min.", monitoring: "RASS or sedation goal, BP, HR (bradycardia, hypotension). Daily TG (hypertriglyceridemia signals PRIS risk), CK, lactate, ABG if PRIS suspected. Hold sedation daily for SAT/SBT." },
  "Dexmedetomidine": { pearls: "α₂-agonist sedation — patient remains arousable, less delirium than propofol/benzo per MENDS, SEDCOM trials. Bradycardia and hypotension common — skip loading dose if hemodynamically marginal. Original FDA label limits to ≤24h but widely used long-term off-label.", dosing: "Loading: 1 mcg/kg over 10 min (often SKIPPED in ICU). Maintenance: 0.2-0.7 mcg/kg/hr titrated to RASS (max 1.5 mcg/kg/hr). Procedural: 1 mcg/kg over 10 min then 0.6 mcg/kg/hr.", monitoring: "RASS, HR (bradycardia), BP (hypotension). Withdrawal symptoms with abrupt discontinuation after >5-7 days." },

  // ===== Phase 3 expansion summaries =====
  "Magnesium Sulfate": { pearls: "ISMP HIGH-ALERT in OB units (eclampsia load doses). Toxicity progression: loss of patellar reflexes (≥10 mg/dL) → respiratory depression (≥15) → cardiac arrest (≥25). Always have IV calcium gluconate at bedside as antidote during high-dose protocols.", dosing: "Eclampsia: 4-6 g IV load over 15-30 min then 1-2 g/hr × 24h post-delivery. Torsades: 1-2 g over 5-15 min. Severe asthma: 2 g over 20 min. Repletion: 1-4 g over 1-4h titrated to serum Mg.", monitoring: "Serum Mg q6h during loading, deep tendon reflexes hourly, respiratory rate, urine output (renal clearance). Hold if reflexes absent or RR <12." },
  "Calcium Gluconate": { pearls: "Preferred over calcium chloride for peripheral lines (chloride is vesicant). 1 g calcium chloride = 3 g calcium gluconate (Ca content). NEVER co-administer with ceftriaxone (precipitation, neonatal black box). Stabilizes cardiac membrane in hyperkalemia but does NOT lower K — pair with insulin/dextrose.", dosing: "Hyperkalemia (cardiac protection): 1-2 g IV over 2-5 min, repeat in 5 min if ECG changes persist. Hypocalcemia: 1-2 g IV over 10-20 min. CCB OD: 1-3 g IV bolus + repeat. Citrate toxicity: titrated.", monitoring: "ECG (peaked T waves resolving), ionized calcium, BP. Watch IV site (tissue necrosis if extravasates)." },
  "Sodium Bicarbonate": { pearls: "AHA 2020 guidelines limit cardiac arrest use to specific scenarios (hyperK, TCA OD, pre-existing severe metabolic acidosis) — routine empiric use NOT recommended (worsens intracellular acidosis). Vesicant if extravasates. Look-alike packaging — confirm before push.", dosing: "Cardiac arrest (selective): 1 mEq/kg IVP. TCA OD: 1-2 mEq/kg bolus + drip 100-150 mEq in 1 L D5W to pH ≥7.5. Severe metabolic acidosis (pH <7.1): 1-2 mEq/kg over 1h. Urinary alkalinization: 150 mEq in 1 L D5W titrated to urine pH 7.5.", monitoring: "ABG q1-2h during titration, electrolytes (causes hypoK, hyperNa, hypoCa), serum pH. ECG (TCA OD)." },
  "Levetiracetam": { pearls: "ESETT trial showed non-inferiority to fosphenytoin and valproate as second-line for status epilepticus — increasingly first-choice given ease of use. Renal dose adjustment (CrCl 30-50 → 50% reduction). Minimal CYP interactions — preferred in transplant patients on immunosuppressants. Behavioral side effects (irritability, depression).", dosing: "Status epilepticus: 60 mg/kg IV load (max 4500 mg) over 10 min. Maintenance: 500-1500 mg q12h. Renal adjust: CrCl 30-50 → 250-750 mg q12h; <30 → 250-500 mg q12h.", monitoring: "Behavioral changes (irritability, depression, suicidality), CBC (rare cytopenias), SCr (dose adjust)." },
  "Fosphenytoin": { pearls: "ALL doses ordered as PE (phenytoin equivalents) — confirm units before giving. Continuous BP and ECG monitoring during loading — hypotension and arrhythmia common. \"Purple glove syndrome\" risk much less than IV phenytoin. IV or IM (advantage over phenytoin).", dosing: "Status epilepticus load: 15-20 mg PE/kg at max 100-150 mg PE/min. Non-emergent load: 10-20 mg PE/kg at max 150 mg PE/min. Maintenance: 4-6 mg PE/kg/day divided q8-12h IV/PO/IM.", monitoring: "Continuous BP and ECG during loading. Free phenytoin level (especially in hypoalbuminemia or renal failure) — corrected total target 10-20 mg/L; free 1-2 mg/L." },
  "Lacosamide": { pearls: "Adjunctive third-line in status epilepticus when first/second-line agents fail. PR interval prolongation — caution or avoid in 2nd/3rd degree AV block. Renal dose adjust for CrCl <30 mL/min. Hepatic adjust for severe impairment. Generally well tolerated; minimal CYP interactions.", dosing: "Status epilepticus: 200-400 mg IV over 15-60 min (loading dose). Maintenance: 100-200 mg IV q12h. Renal: CrCl <30 → max 300 mg/day total. Hepatic severe: max 300 mg/day.", monitoring: "ECG (PR prolongation, AV block), LFTs (hepatic adjust), psychiatric symptoms, SCr." },
  "Tranexamic Acid": { pearls: "CRASH-2 trial: trauma within 3h of injury reduces mortality (NNT 67). WOMAN trial: PPH given within 3h reduces death from bleeding. CRASH-3: TBI within 3h reduces head-injury death. NOT for active intravascular thrombosis or SAH (delayed cerebral ischemia signal). Seizure risk at high doses (>2 g) especially cardiac surgery.", dosing: "Trauma (CRASH-2): 1 g IV over 10 min then 1 g over 8h, must start within 3h of injury. PPH (WOMAN): 1 g IV over 10 min, repeat 1 g if bleeding continues at 30 min. Cardiac surgery: 10-30 mg/kg bolus + maintenance.", monitoring: "Bleeding response, signs of thromboembolism (DVT, PE, MI, stroke). Seizure activity at high cumulative doses." },
  "4-Factor PCC": { pearls: "Warfarin reversal in major bleeding or pre-emergency surgery — reverses INR within 30 min. MUST co-administer vitamin K 5-10 mg IV (PCC is short-acting bridge; vitamin K provides sustained reversal). Thrombosis risk — verify life-threatening bleed indication before use. Includes Factors II, VII, IX, X + Protein C/S + heparin.", dosing: "Pre-treatment INR-based: <4 → 25 units/kg; 4-6 → 35 units/kg; >6 → 50 units/kg. Cap at 5000 units. Bolus at 0.12 mL/kg/min (max 8.4 mL/min).", monitoring: "INR within 30 min and at 6-12h. Signs of thromboembolism. Heparin-induced thrombocytopenia (contains heparin)." },
  "Recombinant Factor VIIa": { pearls: "FDA-approved for hemophilia A/B with inhibitors, congenital Factor VII deficiency, Glanzmann thrombasthenia. OFF-LABEL use (warfarin reversal, trauma, intracranial hemorrhage) is controversial — significant arterial thrombosis risk per CONTROL and other RCTs. Confirm specific indication before use.", dosing: "Hemophilia with inhibitors: 90 mcg/kg IV bolus q2h until hemostasis. Off-label warfarin reversal: 20-40 mcg/kg single dose (KCentra preferred per most guidelines). ICH off-label: dose varies.", monitoring: "Bleeding response, signs of thromboembolism (especially arterial — MI, stroke). LFTs." },
  "Idarucizumab": { pearls: "Specific dabigatran reversal — life-threatening bleed or emergent surgery. Reverses anticoagulant effect within minutes (REVERSE-AD trial). Re-initiate dabigatran 24h post-reversal if clinically appropriate. NOT effective for other DOACs (use andexanet alfa for apixaban/rivaroxaban). Single 5 g dose typically sufficient.", dosing: "5 g IV (two consecutive 2.5 g/50 mL vials) as bolus or infused over 5-10 min each. No renal/hepatic adjustment needed.", monitoring: "Bleeding response, dabigatran level if available, signs of recurrent bleeding (rare rebound)." },
  "Hydrocortisone": { pearls: "Septic shock per Surviving Sepsis when persistent vasopressor requirement (norepi >0.25 mcg/kg/min). Adrenal crisis emergency dose. Glucocorticoid + mineralocorticoid activity (no fludrocortisone needed for adrenal crisis if hydrocortisone used).", dosing: "Septic shock: 200 mg/day (50 mg q6h IV or 200 mg/24h continuous). Adrenal crisis: 100 mg IV bolus then 50 mg IV q6h or 200 mg/24h continuous infusion. Severe asthma: 100-500 mg IV q6h.", monitoring: "Glucose (transient hyperglycemia), BP, electrolytes, infection signs, mental status." },
  "Methylprednisolone": { pearls: "Pulse doses (≥250 mg) infused too rapidly (<30 min) associated with arrhythmia and cardiac arrest. NO mineralocorticoid activity — does NOT replace adrenal cortex (use hydrocortisone for adrenal crisis). Acute spinal cord injury (NASCIS) controversial — not standard of care per modern AANS guidelines.", dosing: "MS exacerbation: 1000 mg IV daily × 3-5 days. Asthma: 60-125 mg IV q6h. Pulse: 1000 mg over 60 min. Transplant rejection: 250-1000 mg/day × 3 days.", monitoring: "Glucose, BP, electrolytes (K wasting), infection signs, GI bleeding (PPI prophylaxis at high doses), psychiatric symptoms." },
  "Insulin Regular": { pearls: "ISMP HIGH-ALERT — independent double-check mandatory. Look-alike vs heparin. NEVER use U-500 IV. Insulin adsorbs to IV tubing — flush line with 20-50 mL of insulin solution before connecting to patient. Hypokalemia common during DKA/HHS treatment — replace aggressively (start K replacement when K <5.3).", dosing: "DKA: 0.1 units/kg IVP load → 0.1 units/kg/hr titrated to glucose decrease 50-75 mg/dL/hr. HHS: 0.1 units/kg/hr (often skip load). Hyperkalemia: 10 units IVP with D50W 25 g (also need albuterol, kayexalate/Lokelma). Periop hyperglycemia: 0.5-2 units/hr.", monitoring: "Glucose hourly during DKA/HHS treatment. K, anion gap, ABG q2-4h. Transition to subQ when anion gap closed and patient eating." },
  "Pantoprazole": { pearls: "Acute upper GI bleed protocol (high-dose continuous): 80 mg load + 8 mg/hr × 72h reduces rebleed risk per multiple meta-analyses. Compatible with most IV solutions. Convert to PO/IV once tolerating diet. Long-term IV use NOT recommended (cost, C. diff, AKI signal).", dosing: "GI bleed: 80 mg IV bolus over 2 min then 8 mg/hr × 72h. Standard PUD/GERD/erosive esophagitis: 40 mg IV q24h over 15 min. Stress ulcer prophylaxis: 40 mg IV q24h.", monitoring: "Hgb/Hct, signs of recurrent bleeding, Mg (chronic PPI hypomagnesemia), C. diff signs in hospital." },
  "Octreotide": { pearls: "Variceal hemorrhage adjunct with endoscopic therapy and antibiotics per AASLD. Carcinoid syndrome flushing/diarrhea control. Bradycardia and hyperglycemia (or hypoglycemia in insulinoma) common. Cholelithiasis with prolonged use. NOT TPN-compatible.", dosing: "Variceal bleed: 50 mcg IV bolus then 25-50 mcg/hr × 3-5 days. Carcinoid crisis: 100-500 mcg IV bolus then continuous. Acromegaly: per LAR depot protocol. Acute pancreatitis: NOT indicated (older controversial use).", monitoring: "Glucose (hypo/hyperglycemia), HR (bradycardia), GI symptoms (gallbladder dysfunction), signs of bleeding response (hematemesis, Hgb/Hct)." }
};

